SELECT Customer.No_, Customer.[Purchase Group], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[Payment Method Code], Customer.[Risk Rating], Customer.[PM Failure Assigned Score], Customer.[Current Risk], Customer.[Updated Date] AS DataAggiornamento, Customer.[valuation Date] AS DataValutazione, [Customer.Due Date] AS DataScadenza, Customer.[Updated Type], Customer.[Skip Credit Info Update], Sum(Val([Detailed Cust_ Ledg_ Entry.Amount])) AS SaldoD
FROM [Detailed Cust_ Ledg_ Entry] INNER JOIN Customer ON [Detailed Cust_ Ledg_ Entry].[Customer No_] = Customer.No_
GROUP BY Customer.No_, Customer.[Purchase Group], Customer.Name, Customer.[Name 2], Customer.Address, Customer.[Post Code], Customer.City, Customer.County, Customer.[Country_region Code], Customer.[VAT Registration No_], Customer.[Fiscal Code], Customer.[Payment Method Code], Customer.[Risk Rating], Customer.[PM Failure Assigned Score], Customer.[Current Risk], Customer.[Updated Date], Customer.[valuation Date], [Customer.Due Date], Customer.[Updated Type], Customer.[Skip Credit Info Update]
HAVING (((Abs((Sum(Val([Detailed Cust_ Ledg_ Entry.Amount])))))>0.01));

